import { defineStore } from 'pinia'
import axios from 'axios'

export const useWorkflowStore = defineStore('workflow', {
  state: () => ({
    workflows: [],
    currentWorkflow: null,
    workflowInstances: [],
    currentInstance: null,
    templates: [],
    isLoading: false,
    error: null
  }),

  getters: {
    getWorkflows: (state) => state.workflows,
    getCurrentWorkflow: (state) => state.currentWorkflow,
    getWorkflowInstances: (state) => state.workflowInstances,
    getCurrentInstance: (state) => state.currentInstance,
    getTemplates: (state) => state.templates,
    getIsLoading: (state) => state.isLoading,
    getError: (state) => state.error
  },

  actions: {
    // 获取工作流列表
    async fetchWorkflows() {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get('/api/workflows/')
        this.workflows = response.data.results || response.data
        // 确保标签字段存在并且是数组
        this.workflows.forEach(workflow => {
          if (!workflow.tags) {
            workflow.tags = []
          } else if (typeof workflow.tags === 'string') {
            try {
              workflow.tags = JSON.parse(workflow.tags)
            } catch (e) {
              workflow.tags = workflow.tags.split(',').map(tag => tag.trim())
            }
          }
        })
      } catch (error) {
        this.error = '获取工作流列表失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 获取单个工作流详情
    async fetchWorkflow(id) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get(`/api/workflows/${id}/`)
        this.currentWorkflow = response.data
        // 确保标签字段存在并且是数组
        if (!this.currentWorkflow.tags) {
          this.currentWorkflow.tags = []
        } else if (typeof this.currentWorkflow.tags === 'string') {
          try {
            this.currentWorkflow.tags = JSON.parse(this.currentWorkflow.tags)
          } catch (e) {
            this.currentWorkflow.tags = this.currentWorkflow.tags.split(',').map(tag => tag.trim())
          }
        }
      } catch (error) {
        this.error = '获取工作流详情失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 保存工作流
    async saveWorkflow(workflow) {
      this.isLoading = true
      this.error = null
      
      try {
        // 确保标签是有效的格式
        const workflowData = { ...workflow }
        if (workflowData.tags && Array.isArray(workflowData.tags)) {
          workflowData.tags = JSON.stringify(workflowData.tags)
        }
        
        let response
        if (workflow.id) {
          // 更新现有工作流
          response = await axios.put(`/api/workflows/${workflow.id}/`, workflowData)
        } else {
          // 创建新工作流
          response = await axios.post('/api/workflows/', workflowData)
        }
        
        const savedWorkflow = response.data
        
        // 确保标签字段是数组
        if (!savedWorkflow.tags) {
          savedWorkflow.tags = []
        } else if (typeof savedWorkflow.tags === 'string') {
          try {
            savedWorkflow.tags = JSON.parse(savedWorkflow.tags)
          } catch (e) {
            savedWorkflow.tags = savedWorkflow.tags.split(',').map(tag => tag.trim())
          }
        }
        
        this.currentWorkflow = savedWorkflow
        return savedWorkflow
      } catch (error) {
        this.error = '保存工作流失败'
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 删除工作流
    async deleteWorkflow(id) {
      this.isLoading = true
      this.error = null
      
      try {
        await axios.delete(`/api/workflows/${id}/`)
        this.workflows = this.workflows.filter(w => w.id !== id)
        if (this.currentWorkflow && this.currentWorkflow.id === id) {
          this.currentWorkflow = null
        }
        return true
      } catch (error) {
        this.error = '删除工作流失败'
        console.error(error)
        return false
      } finally {
        this.isLoading = false
      }
    },

    // 获取工作流模板
    async fetchTemplates() {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get('/api/workflows/templates/')
        this.templates = response.data.results || response.data
        // 确保标签字段存在并且是数组
        this.templates.forEach(template => {
          if (!template.tags) {
            template.tags = []
          } else if (typeof template.tags === 'string') {
            try {
              template.tags = JSON.parse(template.tags)
            } catch (e) {
              template.tags = template.tags.split(',').map(tag => tag.trim())
            }
          }
        })
      } catch (error) {
        this.error = '获取工作流模板失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 获取工作流实例列表
    async fetchWorkflowInstances() {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get('/api/workflows/instances/')
        this.workflowInstances = response.data.results || response.data
      } catch (error) {
        this.error = '获取工作流实例列表失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 获取单个工作流实例详情
    async fetchWorkflowInstance(id) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get(`/api/workflows/instances/${id}/`)
        this.currentInstance = response.data
      } catch (error) {
        this.error = '获取工作流实例详情失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 启动工作流实例
    async startWorkflowInstance(workflowId, parameters) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.post(`/api/workflows/${workflowId}/execute/`, { parameters })
        return response.data
      } catch (error) {
        this.error = '启动工作流实例失败'
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 取消工作流实例
    async cancelWorkflowInstance(instanceId) {
      this.isLoading = true
      this.error = null
      
      try {
        await axios.post(`/api/workflows/instances/${instanceId}/cancel/`)
        if (this.currentInstance && this.currentInstance.id === instanceId) {
          this.currentInstance.status = 'cancelled'
        }
        return true
      } catch (error) {
        this.error = '取消工作流实例失败'
        console.error(error)
        return false
      } finally {
        this.isLoading = false
      }
    },

    // 暂停工作流实例
    async pauseWorkflowInstance(instanceId) {
      this.isLoading = true
      this.error = null
      
      try {
        await axios.post(`/api/workflows/instances/${instanceId}/pause/`)
        if (this.currentInstance && this.currentInstance.id === instanceId) {
          this.currentInstance.status = 'paused'
        }
        return true
      } catch (error) {
        this.error = '暂停工作流实例失败'
        console.error(error)
        return false
      } finally {
        this.isLoading = false
      }
    },
    
    // 恢复工作流实例
    async resumeWorkflowInstance(instanceId) {
      this.isLoading = true
      this.error = null
      
      try {
        await axios.post(`/api/workflows/instances/${instanceId}/resume/`)
        if (this.currentInstance && this.currentInstance.id === instanceId) {
          this.currentInstance.status = 'running'
        }
        return true
      } catch (error) {
        this.error = '恢复工作流实例失败'
        console.error(error)
        return false
      } finally {
        this.isLoading = false
      }
    },

    // 重试工作流步骤
    async retryWorkflowStep(instanceId, stepId) {
      this.isLoading = true
      this.error = null
      
      try {
        await axios.post(`/api/workflows/instances/${instanceId}/steps/${stepId}/retry/`)
        return true
      } catch (error) {
        this.error = '重试工作流步骤失败'
        console.error(error)
        return false
      } finally {
        this.isLoading = false
      }
    }
  }
}) 